const item = $input.first();
const json = item.json ?? {};
const binary = item.binary ?? {};

const from = typeof json.from === 'object'
  ? json.from.text || json.from.value?.[0]?.address || undefined
  : json.from;

const baseMessageId = String(json.messageId || json.messageID || json.uid || `${json.date || Date.now()}-${json.subject || 'email'}`);
const receivedAt = json.date || json.receivedAt;
const subject = json.subject;
const text = json.textPlain || json.text || json.bodyText || '';
const output = [];

function email(partId, partText = '') {
  return {
    messageId: `${baseMessageId}#${partId}`,
    originalMessageId: baseMessageId,
    from,
    subject,
    receivedAt,
    text: partText,
  };
}

if (String(text).trim().length > 0) {
  output.push({
    json: {
      email: email('body', text),
      attachments: [],
    },
  });
}

let attachmentIndex = 0;
for (const [key, meta] of Object.entries(binary)) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  output.push({
    json: {
      email: email(`attachment_${attachmentIndex}`),
      attachments: [
        {
          fileName: meta.fileName || meta.fileNameDecoded || key,
          mimeType: meta.mimeType || 'application/octet-stream',
          dataBase64: buffer.toString('base64'),
        },
      ],
    },
  });
  attachmentIndex += 1;
}

return output;

const item = $input.first();

return [
  {
    json: {
      tripcalUrl: 'https://ralfw-tripcal.netlify.app/api/ingest-email-background',
      tripcalToken: 'REPLACE_WITH_EMAIL_INGEST_TOKEN',
      payload: item.json,
    },
  },
];

const item = $input.first();
const response = item.json ?? {};

if (!response.error) {
  return [];
}

const config = $('TripCal Config').first().json;
const payload = config.payload ?? {};
const error = response.error;

return [
  {
    json: {
      originalEmail: payload.email,
      endpoint: config.tripcalUrl,
      httpStatus: error.httpCode || error.statusCode || error.code || 'request_error',
      httpStatusText: error.message || error.name || 'TripCal request failed',
      responseBody: error.description || error.response?.body || error.stack || JSON.stringify(error),
      attachments: payload.attachments || [],
    },
  },
];

const item = $input.first();
const email = item.json.originalEmail ?? {};
const from = String(email.from || '').trim();
const match = from.match(/<([^>]+)>/) || from.match(/([^\s<>]+@[^\s<>]+)/);
const toEmail = match ? match[1] : from;

const originalSubject = email.subject || '(ohne Betreff)';
const originalMessageId = email.originalMessageId || email.messageId;
const attachmentNames = Array.isArray(item.json.attachments)
  ? item.json.attachments.map((attachment) => attachment.fileName).filter(Boolean)
  : [];

const body = [
  'TripCal konnte eine weitergeleitete E-Mail nicht verarbeiten.',
  '',
  `Betreff: ${originalSubject}`,
  `Von: ${from || 'unbekannt'}`,
  `Empfangen: ${email.receivedAt || 'unbekannt'}`,
  `TripCal Endpoint: ${item.json.endpoint}`,
  '',
  `HTTP Status: ${item.json.httpStatus} ${item.json.httpStatusText || ''}`.trim(),
  '',
  'Antwort der TripCal API:',
  item.json.responseBody || '(keine Antwort)',
  '',
  attachmentNames.length > 0 ? `Anhänge: ${attachmentNames.join(', ')}` : '',
].filter((line) => line !== '').join('\n');

return [
  {
    json: {
      toEmail,
      fromEmail: 'tripcal-documents@work-with-ease.eu',
      subject: `TripCal Fehler: ${originalSubject}`,
      text: body,
      headers: originalMessageId
        ? `In-Reply-To: ${originalMessageId}\nReferences: ${originalMessageId}`
        : '',
    },
  },
];
